 404→        *,
 405→        opinions!opinion_id(id, opinion, user_id, created_at),
 406→        users!sender_id(name, user_email, image_url, id, badge)
 407→        `)
 408→    .eq('receiver_id', receiverId)
 409→    .eq('read', false)
 410→    .order('created_at', {ascending: false})
 411→    .order('id', {ascending: false})
 412→    .limit(fetchLimit)
