 440→    if(journalIds.length > 0){
 441→        const [hasLiked, hasBookMarked] = await Promise.all([
 442→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
 443→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
