 445→
 446→        if(hasLiked.error || hasBookMarked.error){
 447→            console.error('error', hasLiked.error || hasBookMarked.error)
 448→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
 449→        }
 450→        hasLikedResult = hasLiked.data || [];
