317→const evaluateShareImageCandidate = (rawUrl) => {
318→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
319→    if (!absoluteUrl) {
320→        return {
321→            ok: false,
322→            reason: 'invalid_or_non_http_url',
323→            resolvedUrl: null,
324→        };
325→    }
326→
327→    let path = '';
328→    try {
329→        const parsed = new URL(absoluteUrl);
330→        path = String(parsed.pathname || '').toLowerCase();
331→    } catch {
332→        return {
333→            ok: false,
334→            reason: 'invalid_resolved_url',
335→            resolvedUrl: null,
336→        };
337→    }
338→
339→    if (path.endsWith('.svg')) {
340→        return {
341→            ok: false,
342→            reason: 'svg_not_supported_for_share_image',
343→            resolvedUrl: absoluteUrl,
344→        };
345→    }
346→
347→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
348→        return {
349→            ok: false,
350→            reason: 'unsafe_remote_url',
351→            resolvedUrl: absoluteUrl,
352→        };
353→    }
354→
355→    return {
356→        ok: true,
357→        reason: 'ok',
358→        resolvedUrl: absoluteUrl,
359→    };
360→};
