362→const fetchRemoteImageBuffer = async (imageUrl) => {
363→    const controller = new AbortController();
364→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
365→
366→    try {
367→        const response = await fetch(imageUrl, {
368→            method: 'GET',
369→            redirect: 'follow',
370→            signal: controller.signal,
371→            headers: {
372→                Accept: 'image/*,*/*;q=0.8',
373→                'Accept-Encoding': 'identity',
374→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
375→            },
376→        });
377→
378→        if (!response.ok) {
379→            throw new Error(`upstream image status ${response.status}`);
380→        }
381→
382→        const finalUrl = response.url || imageUrl;
383→        if (!isSafeRemoteImageUrl(finalUrl)) {
384→            throw new Error('upstream redirected to unsafe url');
385→        }
386→
387→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
388→        if (!contentType.startsWith('image/')) {
389→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
390→        }
391→        if (contentType.includes('image/svg')) {
392→            throw new Error('svg images are not used for share previews');
393→        }
394→
395→        const headerContentLength = Number(response.headers.get('content-length'));
396→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
397→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
398→        }
399→
400→        const arrayBuffer = await response.arrayBuffer();
401→        const buffer = Buffer.from(arrayBuffer);
402→
403→        if (!buffer.length) {
404→            throw new Error('upstream image is empty');
405→        }
406→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
407→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
408→        }
409→
410→        return {
411→            buffer,
412→            contentType,
413→            byteLength: buffer.length,
414→            finalUrl,
415→        };
416→    } finally {
417→        clearTimeout(timeout);
418→    }
419→};
