668→app.get('/share/post/:journalId/image', async (req, res) => {
669→    const { journalId } = req.params;
670→    await ensureShareFonts();
671→    const debugMode = isShareImageDebugRequest(req);
672→    const debugPayload = {
673→        ok: false,
674→        fallback: false,
675→        journalId,
676→        stage: 'start',
677→        reason: '',
678→        meta: {
679→            imageCandidateSource: null,
680→            imageCandidateRaw: null,
681→            imageCandidateResolved: null,
682→            upstreamFinalUrl: null,
683→            upstreamContentType: null,
684→            upstreamBytes: null,
685→            outputBytes: null,
686→        },
687→    };
688→
689→    const fallbackWithReason = (reason) => {
690→        debugPayload.ok = false;
691→        debugPayload.fallback = true;
692→        debugPayload.stage = 'fallback';
693→        debugPayload.reason = reason;
694→        if (debugMode) {
695→            return sendShareImageDebug(res, debugPayload);
696→        }
697→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
698→    };
699→
700→    try {
701→        const journal = await getShareJournal(journalId);
702→        debugPayload.stage = 'journal_loaded';
703→        if (!journal) {
704→            return fallbackWithReason('journal_not_found');
705→        }
706→
707→        const shareMeta = buildShareMetaFromJournal(journal);
708→        debugPayload.stage = 'candidate_extracted';
709→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
710→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
711→
712→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
713→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
714→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
715→            return fallbackWithReason(candidateEvaluation.reason);
716→        }
717→
718→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
719→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
720→            return fallbackWithReason('candidate_is_default_fallback');
721→        }
722→
723→        debugPayload.stage = 'fetching_upstream';
724→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
725→        debugPayload.stage = 'upstream_loaded';
726→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
727→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
728→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
729→
730→        debugPayload.stage = 'converting_image';
731→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
732→        debugPayload.stage = 'converted_image';
733→        debugPayload.ok = true;
734→        debugPayload.reason = 'ok';
735→        debugPayload.meta.outputBytes = ogImageBuffer.length;
736→
737→        if (debugMode) {
738→            return sendShareImageDebug(res, debugPayload);
739→        }
740→
741→        res.set('Content-Type', 'image/jpeg');
742→        res.set('Cache-Control', 'public, max-age=3600');
743→        return res.send(ogImageBuffer);
744→    } catch (err) {
745→        debugPayload.stage = 'error';
746→        debugPayload.reason = err?.message || 'unknown_error';
747→        console.error('share image route error:', err?.message || err);
748→        return fallbackWithReason(debugPayload.reason);
749→    }
750→});
